VALUES
  ('judicial-d35ec6db-moex-00277', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於短期消滅時效之敘述，何者錯誤？', '["僱傭關係所涉薪資之請求權，因2年間不行使而消滅", "商人、製造人、手工業人所供給之商品及產物之代價，因2年間不行使而消滅", "會計師之報酬及其墊款請求權之行使，因2年間不行使而消滅", "醫師之診費、報酬及其墊款請求權之行使，因2年間不行使而消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00278', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲將1部電動機車出售於乙，乙又將該車贈送並移轉所有權予丙。後來發現甲乃受監護宣告之人， 但乙、丙不知此情事。下列敘述，何者錯誤？', '["甲乃受監護宣告之人，故其所為之債權行為及物權行為皆無效", "乙贈與丙之電動機車，因由受監護宣告之甲處所購得，故乙丙間之贈與契約無效，移轉電動機 車所有權之行為，亦無效", "善意的乙已將電動機車無償讓與丙，故不負返還之責", "善意的丙因善意受讓取得電動機車所有權，其受有利益雖有法律上原因，但基於衡平保護甲之 利益，甲得類推適用民法第183條規定，向丙請求返還電動機車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00279', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '民法第 225 條規定因不可歸責於債務人之事由，致嗣後給付不能之法律效果。下列敘述，何者 錯誤？', '["債務人免給付義務", "債權人得向債務人請求讓與其對第三人之損害賠償請求權", "債權人得向債務人請求交付其因給付不能所受領之賠償物", "債權人得向債務人請求損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00280', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲乙丙共有A地，其應有部分各為1/3。甲未經乙丙同意，而擅自在A地上架設太陽能板。試問： 乙丙不得對甲主張下列何種權利？', '["因債務不履行之損害賠償請求權", "共有物返還請求權", "不當得利請求權", "侵權行為損害賠償請求權 20420 20520"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00281', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲因赴外地工作，遂將其所有之A車交付予乙，由乙為其保管。雙方並約定乙每週短暫發動引擎 兩次，以免A車因長時間停放而受損。下列敘述，何者正確？', '["若甲乙就A車之返還，定有返還期限時，則甲不得隨時請求返還", "若甲乙就A車之返還，未定有返還期限時，則乙得隨時返還", "若乙未經甲之同意，即逕取A車載友人丙出遊。途中因另一駕駛丁未注意車前狀況而撞上等紅 燈之乙，致A車車尾凹陷，則乙就A車所生之損害，對甲不負損害賠償責任", "若乙未受有報酬，仍應以善良管理人之注意保管A車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00282', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲發現乙有珍貴花卉種籽，暗自取走後，將種籽栽種於甲之母丙的農地上。半年後花朵盛開，該 花朵現為何人所有？', '["甲", "乙", "丙", "乙丙共有"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00283', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲向乙借款，並將所有之A屋設定最高限額抵押權予乙。下列敘述，何者錯誤？', '["乙將對甲之債權讓與給丙，該最高限額抵押權並不隨同移轉給丙", "乙對甲之債權如歸於消滅，該最高限額抵押權亦隨之消滅", "該最高限額抵押權不因乙死亡而消滅", "乙實行抵押權之費用不計入抵押權擔保債權之最高限額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00284', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於民法區分所有建築物規定之敘述，何者錯誤？', '["區分所有建築物，乃數人區分一建築物而各專有其一部，就專有部分有單獨所有權，並就該建 築物及其附屬物之共同部分共有之建築物", "專有部分與其所屬之共有部分及其基地之權利，得分離而為移轉或設定負擔", "共有部分除法律另有規定外，得經規約之約定供區分所有建築物之特定所有人使用", "專有部分得經其所有人之同意，依規約之約定供區分所有建築物之所有人共同使用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00285', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於普通地上權地租之敘述，何者錯誤？', '["地上權定有期限，而有支付地租之約定者，地上權人得支付未到期之2年分地租後，拋棄地上權", "地上權未定有期限，而有支付地租之約定者，地上權人得支付未到期之1年分地租後，拋棄地 上權", "地上權設定後，因土地價值之昇降，依原定地租給付顯失公平者，當事人得請求法院增減之", "土地所有權讓與時，已預付之地租，非經登記，不得對抗第三人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00286', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲患有思覺失調症（原稱精神分裂症），時癒時發，經甲母乙之協助隱瞞，甲於某年4月1日成功與 丙結婚。丙結婚次月1 日始發現上開情節，丙於同年12月1日訴請撤銷甲丙之結婚，是否有理？', '["無理，丙發見詐欺後起訴，已逾6個月", "有理，乙為第三人，不得對表意人為詐欺", "有理，丙發見詐欺後起訴，未逾1年", "有理，甲非明知第三人為詐欺，但與有過失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
